INSERT INTO `wp_options` (`option_id`,`option_name`,`option_value`,`autoload`) VALUES('11619','f3477252feca5b8af0f744b11b1d02bd','a:2:{s:7:\"timeout\";i:1774219281;s:5:\"value\";O:8:\"stdClass\":15:{s:11:\"new_version\";s:5:\"2.0.6\";s:14:\"stable_version\";s:5:\"2.0.6\";s:4:\"name\";s:18:\"Fluent Support Pro\";s:4:\"slug\";s:18:\"fluent-support-pro\";s:3:\"url\";s:54:\"https://wpmanageninja.com/products/fluent-support-pro/\";s:12:\"last_updated\";s:19:\"2026-03-16 15:58:12\";s:8:\"homepage\";s:54:\"https://wpmanageninja.com/products/fluent-support-pro/\";s:7:\"package\";s:234:\"https://wpmanageninja.com/edd-sl/package_download/MTc3NDI0MjY4MTo4YmQ4Mzc3ZDA2YmMzYmRmYmVkNTY5ZjAzN2MyMzIxMzo2NjE4OTY4OmI1ZGE5ZmFiZDJlMmMzMjI4Zjk4ODIyYzY2ODYxNzMxOmh0dHBzQC8vc3RhZ2luZy02OGE1LWluZGl0ZWNoc2l0ZXMud3Bjb21zdGFnaW5nLmNvbTow\";s:13:\"download_link\";s:234:\"https://wpmanageninja.com/edd-sl/package_download/MTc3NDI0MjY4MTo4YmQ4Mzc3ZDA2YmMzYmRmYmVkNTY5ZjAzN2MyMzIxMzo2NjE4OTY4OmI1ZGE5ZmFiZDJlMmMzMjI4Zjk4ODIyYzY2ODYxNzMxOmh0dHBzQC8vc3RhZ2luZy02OGE1LWluZGl0ZWNoc2l0ZXMud3Bjb21zdGFnaW5nLmNvbTow\";s:8:\"sections\";a:2:{s:11:\"description\";s:24:\"FluentSupport Pro Plugin\";s:9:\"changelog\";s:5814:\"<p><strong>= 2.0.6 (Date: March 05, 2026) =</strong></p>\n<p>* Updated: Core PHP framework</p>\n<p>* Added: Zendesk migration improvement to collect archived tickets and resume previous migrations</p>\n<p>* Fixed: Onboarding dark mode design issue</p>\n<p>* Fixed: Bulk option checkbox now visible by default</p>\n<p>* Fixed: Ticket list not updating after bulk actions</p>\n<p>* Fixed: File upload limit validation issue after deleting previously uploaded files</p>\n<p>* Fixed: WordPress admin bar overlapping Fluent Support menu</p>\n<p>* Fixed: Agent reply count in reports incorrectly includes internal notes</p>\n<p>* Fixed: Error when navigating directly to a ticket URL due to window.history.state being null</p>\n<p>Â </p>\n<p><strong>= 2.0.5 (Date: March 02, 2026) =</strong></p>\n<p>* Added: Admin Dashboard Dark Mode</p>\n<p>* Added: Support for OpenAI GPT-5.2 &amp; GPT-5.2 Chat models</p>\n<p>* Added: View Tickets (Read Only) permission</p>\n<p>* Improved: Faster ticket list loading</p>\n<p>* Improved: Optimized large-scale Zendesk migration</p>\n<p>* Fixed: Draft Reply permission issue</p>\n<p>* Fixed: Attachment links during ticket merge</p>\n<p>* Fixed: Ticket content unordered list formatting</p>\n<p>* Fixed: Integration settings save button visibility</p>\n<p>* Fixed: âWaiting Sinceâ tooltip date display</p>\n<p>* Fixed: Saved Replies left menu link</p>\n<p>* Fixed: Login page styling issue</p>\n<p>* Fixed: Date range picker responsive layout</p>\n<p><strong>= 2.0.2 (Date: February 09, 2026) =</strong></p>\n<p>* Fixed an issue where current ticket watchers were not displaying in the ticket list.</p>\n<p>* Fixed an issue where ticket merging could fail from the ticket view page.</p>\n<p>* Fixed an issue where reCAPTCHA settings were not saving properly.</p>\n<p>* Fixed a responsiveness issue with the bulk actions bar in the ticket list.</p>\n<p>* Fixed issues related to ticket migration.</p>\n<p>* Fixed a customer profile update issue by treating customer IP fields as strings.</p>\n<p>* Fixed a styling issue with the Ticket Merge dialog buttons.</p>\n<p><strong>= 2.0.1 (Date: February 06, 2026) =</strong></p>\n<p>* Improved onboarding completion UI and post-onboarding navigation</p>\n<p>* Improved sanitization and validation handling</p>\n<p>* Fixed Saved Replies modal showing stale content when editing</p>\n<p><strong>= 2.0.0 (Date: February 05, 2026) =</strong></p>\n<p>* Complete admin interface redesign with a modern layout.</p>\n<p>* Full RTL (Right-to-Left) language support across the interface.</p>\n<p>* Fully mobile-responsive experience across all modules.</p>\n<p>* Revamped menu structure with dropdowns for better organization.</p>\n<p>* Responsive hamburger menus for Main Menu, Settings, and Reports.</p>\n<p>* Drag &amp; Drop Image Upload for tickets.</p>\n<p>* Ticket List Display Settings: manage layout and element visibility directly from the Display Settings icon.</p>\n<p>* Compact Ticket List Layout for faster scanning and higher information density.</p>\n<p>* Keyboard Shortcuts: Enable via Plugin Settings â Global Settings â Enable Keyboard Shortcuts. Click âKeyboard Shortcutsâ to view all available commands.</p>\n<p>* Improved Frontend Support Portal responsiveness and theme compatibility.</p>\n<p>* Refactored Customer Portal SCSS variables for easier dark mode implementation.</p>\n<p>* Updated core PHP framework; resolved PHP 8.4 compatibility issues.</p>\n<p>* Improved input sanitization and validation.</p>\n<p>* Migrated components to the Options API and refactored Vue components for better performance.</p>\n<p>* Prevented unnecessary API calls in the Reports module.</p>\n<p>* Separated personal reports from agent performance reports.</p>\n<p>* Added Reports Stats API for product/business-specific insights.</p>\n<p>* Selected date range persists when switching report tabs.</p>\n<p>* Resolved issue where pressing Enter caused page reload instead of submitting forms.</p>\n<p>* Fixed Block Editor styles not applying correctly on Customer Portal.</p>\n<p>* Fixed WordPress 6.9 admin text editor toolbar compatibility issues.</p>\n<p>* Fixed database table error when the Activity Log feature was disabled.</p>\n<p>* Fixed auto password generation issue for new users with empty password fields.</p>\n<p><strong>= 1.10.4 (Date: November 21, 2025) =</strong></p>\n<p>- Fixed: Issue with attachments not showing from third-party storage.</p>\n<p>- Updated License Server</p>\n<p>Â </p>\n<p><strong>= 1.10.3 (Date: November 17, 2025) =</strong></p>\n<p>* Fixed: Paid Memberships Pro widget was not visible for some customers.</p>\n<p><strong>= 1.10.1 (Date: November 03, 2025) =</strong><br />* Fixed: Fixed undefined safeUnserialize method error</p>\n<p><strong>= 1.10.0 (Date: October 23, 2025) =</strong></p>\n<ul>\n<li>Added: Fluent Cart product purchase widget in the ticket sidebar.</li>\n<li>Added: Fluent Cart product and order options in custom fields.</li>\n<li>Added: Workflow trigger based on Fluent Cart product and order from custom fields.</li>\n<li>Added: Option to integrate the customer portal into the Fluent Cart customer dashboard.</li>\n<li>Added: Multi-select option for product filtering in tickets.</li>\n<li>Improved: Refined plugin performance for increased speed and efficiency.</li>\n</ul>\n<p><strong>= 1.9.2 (Date: August 20, 2025) =</strong></p>\n<ul>\n<li>Added: Product assignment to tickets in Workflow Actions.</li>\n<li>Added: Support for custom field data in Outgoing Webhooks.</li>\n<li>Improved: Click-to-copy shortcode functionality on the Global Settings page.</li>\n<li>Improved: Smart code selection dropdown in Email Settings with click-to-insert functionality in WP Editor.</li>\n<li>Improved: Dash icon updated.</li>\n<li>Fixed: CSRF issue fixed on Report Export - nonce verification.</li>\n<li>Fixed: Error during AI activity log cleanup.</li>\n</ul>\";}s:7:\"banners\";s:183:\"a:2:{s:3:\"low\";s:70:\"https://ps.w.org/fluent-support/assets/banner-1544x500.png?rev=3136133\";s:4:\"high\";s:70:\"https://ps.w.org/fluent-support/assets/banner-1544x500.png?rev=3136133\";}\";s:5:\"icons\";s:158:\"a:2:{s:2:\"2x\";s:59:\"https://ps.w.org/fluent-support/assets/icon.svg?rev=2628677\";s:2:\"1x\";s:59:\"https://ps.w.org/fluent-support/assets/icon.svg?rev=2628677\";}\";s:15:\"license_message\";s:19:\"Invalid License Key\";s:14:\"license_status\";s:7:\"invalid\";s:7:\"success\";b:1;}}','off');
